import{_ as r,o as t,c as e,ai as s}from"./chunks/framework.CaiDwmc7.js";const p=JSON.parse('{"title":"微服务常见高频问题与选型","description":"","frontmatter":{},"headers":[],"relativePath":"framework/microservice-faq.md","filePath":"framework/microservice-faq.md"}'),n={name:"framework/microservice-faq.md"};function i(l,o,a,g,c,d){return t(),e("div",null,[...o[0]||(o[0]=[s('<h1 id="微服务常见高频问题与选型" tabindex="-1">微服务常见高频问题与选型 <a class="header-anchor" href="#微服务常见高频问题与选型" aria-label="Permalink to “微服务常见高频问题与选型”">​</a></h1><hr><h3 id="❓-面试官-微服务之间是怎么进行通信的-你们用的哪种" tabindex="-1">❓ 面试官：微服务之间是怎么进行通信的？你们用的哪种？ <a class="header-anchor" href="#❓-面试官-微服务之间是怎么进行通信的-你们用的哪种" aria-label="Permalink to “❓ 面试官：微服务之间是怎么进行通信的？你们用的哪种？”">​</a></h3><p><em>频率：🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> 微服务通信主要分为<strong>同步调用</strong>和<strong>异步调用</strong>。我们项目里，强依赖且需要立刻拿到结果的查询走<strong>同步的 HTTP（OpenFeign）</strong>；不需要立刻拿到结果、或者为了解耦削峰的操作走<strong>异步的 MQ（如 RocketMQ/RabbitMQ）</strong>。</p><p><strong>📝 详细通信方式盘点：</strong></p><ol><li><strong>HTTP/RESTful（目前最主流的同步方式）</strong>： <ul><li>代表组件：<strong>OpenFeign</strong>、RestTemplate。</li><li>优点：协议通用、跨语言、基于 JSON 调试极其方便（Postman 直接调）。</li><li>缺点：HTTP 协议头部比较臃肿，性能一般。</li></ul></li><li><strong>RPC 协议（高性能的同步方式）</strong>： <ul><li>代表组件：<strong>Dubbo</strong>、gRPC。</li><li>优点：底层基于 TCP 长连接，使用自研的二进制序列化（如 Hessian、Protobuf），报文极小，性能比 HTTP 快很多。</li><li>缺点：调试相对麻烦（不能直接用浏览器发请求），多语言支持不如 HTTP（虽然现在 gRPC 很好）。</li></ul></li><li><strong>消息队列（MQ，异步解耦最佳实践）</strong>： <ul><li>如果 A 服务调用 B 服务，A 不需要等 B 返回结果，或者为了防止 B 挂了拖死 A，就应该把调用改成往 MQ 里扔一条消息，让 B 自己去排队消费。</li></ul></li></ol><hr><h3 id="❓-面试官-在微服务架构下-用户登录的-session-状态怎么共享-网关是怎么做鉴权的-【中高级】" tabindex="-1">❓ 面试官：在微服务架构下，用户登录的 Session 状态怎么共享？网关是怎么做鉴权的？【中高级】 <a class="header-anchor" href="#❓-面试官-在微服务架构下-用户登录的-session-状态怎么共享-网关是怎么做鉴权的-【中高级】" aria-label="Permalink to “❓ 面试官：在微服务架构下，用户登录的 Session 状态怎么共享？网关是怎么做鉴权的？【中高级】”">​</a></h3><p><em>频率：🔥🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> 在微服务下我们<strong>彻底抛弃了传统的 JVM Session</strong>，因为服务是集群部署的，Session 无法在多台机器间共享。目前行业标配是采用 <strong>“网关统一鉴权 + JWT / Redis Token”</strong> 的方案。</p><p><strong>📝 详细鉴权流转过程（面试高分模板）：</strong></p><p><strong>方案：Gateway + JWT 无状态方案</strong></p><ol><li><strong>登录阶段</strong>：用户携带账号密码请求登录。网关将请求路由到 <code>AuthService（认证服务）</code>。认证通过后，<code>AuthService</code> 使用用户的 ID、角色等信息生成一个 <strong>JWT（JSON Web Token）</strong>，并用服务器的私钥对其签名，最后返回给前端。</li><li><strong>请求阶段</strong>：前端把 JWT 放到 HTTP 请求头的 <code>Authorization: Bearer &lt;token&gt;</code> 里。</li><li><strong>网关拦截阶段（核心防线）</strong>： <ul><li>请求到达 <strong>Gateway 网关</strong>。</li><li>网关配置了一个 <code>GlobalFilter（全局过滤器）</code>。它会拦截请求，拿出请求头里的 JWT。</li><li>网关使用公钥验证这个 JWT 的签名是否合法、是否过期。</li><li><strong>如果非法</strong>，网关直接返回 401，请求根本不会打到后面的微服务，保护了内部系统。</li><li><strong>如果合法</strong>，网关会把 JWT 里解析出来的 <code>userId</code> 塞进请求的 <strong>Header</strong> 里，然后放行。</li></ul></li><li><strong>微服务接收阶段</strong>：下游具体的业务微服务（如订单服务），只需要通过 <code>request.getHeader(&quot;userId&quot;)</code> 就能知道当前是谁在操作，完全不需要自己再去连数据库或校验 Token。</li></ol><p><strong>🌟 面试加分项（JWT 的坑点）：</strong> &quot;面试官您好，虽然纯 JWT 方案很轻量，但它有一个致命缺陷：<strong>无法主动踢人下线（Token 签发后在过期前无法作废）</strong>。 所以在我们公司实际落地的架构中，我们采用了 <strong>JWT + Redis 的混合模式</strong>： 用户登录后，生成的 JWT 依然返回给前端，同时我们会把这个 <code>Token</code> 作为 Key 存入 Redis 并设置过期时间。网关不仅要校验 JWT 的签名合法性，还要去 Redis 里查一下这个 Token 还在不在。如果我们想封禁某个用户，只需把 Redis 里的 Token 删掉，网关校验就会失败，完美实现了<strong>踢人下线功能</strong>。&quot;</p><hr><h3 id="❓-面试官-如果不用-seata-你们还有其他方法解决分布式事务吗-可靠消息最终一致性-【高级】" tabindex="-1">❓ 面试官：如果不用 Seata，你们还有其他方法解决分布式事务吗？（可靠消息最终一致性）【高级】 <a class="header-anchor" href="#❓-面试官-如果不用-seata-你们还有其他方法解决分布式事务吗-可靠消息最终一致性-【高级】" aria-label="Permalink to “❓ 面试官：如果不用 Seata，你们还有其他方法解决分布式事务吗？（可靠消息最终一致性）【高级】”">​</a></h3><p><em>频率：🔥🔥🔥🔥</em></p><p><strong>💡 一句话总结（先抛结论）：</strong> Seata 的 AT 模式本质上还是偏向强一致性，性能还是会有所损耗。在高并发的互联网 C 端场景（如支付、下单）中，我们通常采用<strong>“基于 MQ 的可靠消息最终一致性”</strong>方案。它的核心是：<strong>允许短暂的数据不一致，但保证最终所有节点的数据一定是对的</strong>。</p><p><strong>📝 详细落地实战（以 RocketMQ 事务消息为例）：</strong> 假设业务场景是：A 服务（订单服务）负责创建订单，B 服务（积分服务）负责加积分。</p><ol><li><strong>A 服务发送“半消息”</strong>：A 服务在执行本地创建订单的 SQL 之前，先向 RocketMQ 发送一条“加积分”的 Half 消息。此时这个消息对 B 服务是不可见的。</li><li><strong>A 服务执行本地事务</strong>：A 收到 MQ 的确认后，开始执行本地的数据库操作（<code>insert into order</code>）。</li><li><strong>A 服务提交/回滚消息</strong>： <ul><li>如果 A 本地 SQL 执行<strong>成功</strong>，向 MQ 发送 <code>Commit</code>。此时该消息变成对 B 可见，B 就能消费它去加积分了。</li><li>如果 A 本地 SQL 执行<strong>报错</strong>，向 MQ 发送 <code>Rollback</code>。MQ 会把这条半消息直接丢弃，B 不会加积分。（订单没建，积分也没加，数据一致）。</li></ul></li><li><strong>极端情况兜底（MQ 回查机制，核心亮点）</strong>： <ul><li>如果在第 3 步，A 执行完本地 SQL 后<strong>突然宕机了</strong>，没来得及发 Commit 或 Rollback 怎么办？</li><li>RocketMQ 等了一会儿，发现这条半消息还没确切状态，它就会主动发起 <strong>回查（Check）</strong>，调用 A 服务暴露的一个回查接口：“兄弟，你刚才那个订单建成功了吗？”</li><li>A 服务的代码里，去数据库查一下那个订单号。如果查到了，说明成功了，补发 Commit；查不到，说明之前事务回滚了，补发 Rollback。</li></ul></li><li><strong>消费端兜底</strong>：B 服务消费这条消息去加积分。为了防止消费失败，B 会利用 MQ 的<strong>重试机制</strong>一直试。并且 B 服务的加积分接口必须做好<strong>幂等性（防重）</strong>设计，防止重复加分。</li></ol>',21)])])}const m=r(n,[["render",i]]);export{p as __pageData,m as default};
